/**
 * Represents a Logger utility for structured message recording.
 *
 * Suitable for creating a dedicated logger instance.
 * Types originate from the Dynatrace Logger SDK.
 */
/** @internal */
export type GlobalDtRuntimeWithLogger = typeof globalThis & {
    dtRuntime?: {
        logger?: DtRuntimeLogger;
    };
};
/** @internal */
export interface DtRuntimeLogger {
    createLogger(loggerName: string): Readonly<LoggerV1>;
    createLoggerFactory(options: {
        context: LoggerContext;
    }): LoggerFactoryV1;
    createLoggerV2(loggerName: string): Logger;
    createLoggerFactoryV2(options: {
        context: LoggerContext;
    }): LoggerFactory;
}
/** @internal */
export interface Logger {
    info: (message: string, error?: unknown) => void;
    warn: (message: string, error?: unknown) => void;
    error: (message: string, error?: unknown) => void;
}
/** @internal */
export interface LoggerV1 {
    info: (message: string, error?: any) => void;
    warn: (message: string, error?: any) => void;
    error: (message: string, error?: any) => void;
}
/** @internal */
export interface LogOptions {
    error?: any;
    details?: Record<string, unknown>;
}
/** @internal */
export interface LoggerContext {
    id: string;
    version: string;
}
/** @internal */
export interface LoggerFactoryV1 {
    createLogger: (name: string) => LoggerV1;
}
/** @internal */
export interface LoggerFactory {
    createLogger: (name: string) => Logger;
}
